        public CalculoPolilinea(ref dsApp a, int opcion, double ratio, ref int giro, ref int sentido, ref int gl,double dist, ref int p_dis) {
            try {
                bool dibujar = true;
                if (a.Polilinea.Rows.Count == 0) {
                    dibujar = false;
                    Set_Polilinea(ref a);
                }
                a.Polilinea3d.Clear();
                this.ratio = ratio;
                foreach (DataRow r in a.Polilinea.Rows) {

                    string x = (string)r["X"];
                    string y = (string)r["Y"];

                    Punto p = new Punto(new Point2d(double.Parse(x), double.Parse(y)));
                    polilinea.Add(p);
                }
                RellenarDatos();
                p_dis=Eliminar_Distancia_m(dist);
                FiltradoDisrupcion(false, ref giro);
                FiltradoCambioSentido(false, ref sentido);
                FiltradoGiroLongitud(ratio, false, ref gl);
            } catch (System.Exception ex) {
                throw new System.Exception("Debe realizar primero la busqueda para realizar la exportacion", ex);

            }
        }
