                        lcp = LCp[i];
                    } else {
                        lcp = LC[i];
                    }


                    for (int t = 0; t < LC.Count; t++) {
                        if (LC[t].Item5 == pos + 1) {
                            lc1 = LC[t];
                            if (LCp.Count < t) {
