            for (int i = 0; i < polilinea.Count - 1; i++) {
                Punto p = polilinea[i];
                if (i == 0) {
                    polilinea_temp.Add(p);
                } else {
                    if (polilinea[i + 1].secuenciagiro == 1 && (polilinea[i + 1].R < p.R && polilinea[i + 1].R < polilinea[i + 2].R)) {
                        contador++;


