        public void addText2D(string iTexto, double iX, double iY, double iAltura, double iRotateRadianes, int iColorIndex, string iLayer) {
            using (DocumentLock miDockLock = oCadManager.thisEditor.Document.LockDocument()) {
                using (Transaction tr = oCadManager.StartTransaction()) {

                    BlockTable miBlockTable = tr.GetObject(oCadManager.thisBase.BlockTableId, OpenMode.ForRead) as BlockTable;

                    BlockTableRecord miBlockTableRec = tr.GetObject(miBlockTable[BlockTableRecord.ModelSpace], OpenMode.ForWrite) as BlockTableRecord;

                    DBText miText = new DBText();

                    miText.SetDatabaseDefaults();

                    miText.ColorIndex = iColorIndex;

                    miText.Height = iAltura;

                    //////////////////////////////////////////////////////
                    miText.HorizontalMode = TextHorizontalMode.TextLeft;

                    miText.VerticalMode = TextVerticalMode.TextVerticalMid;
                    ///////////////////////////////////////////////////////

                    miText.Position = new Point3d(iX, iY, 0);

                    miText.AlignmentPoint = miText.Position;

                    miText.Rotation = iRotateRadianes;

                    miText.TextString = iTexto;
                    engCadNet.oLayer.addLayer(iLayer, (short)iColorIndex, false);
                    miText.Layer = iLayer;

                    miBlockTableRec.AppendEntity(miText);

                    tr.AddNewlyCreatedDBObject(miText, true);

                    tr.Commit();

                }
            }

        }
        public void Dibujar_entidad(int i) {
            if (componentes[i].Tipo == 1) {
                tadLayShare.puntos.Punto3d p1 = new Punto3d(componentes[i].lista_puntos[0].p.X, componentes[i].lista_puntos[0].p.Y, 0);
                tadLayShare.puntos.Punto3d p2 = new Punto3d(componentes[i].lista_puntos[componentes[i].lista_puntos.Count - 1].p.X, componentes[i].lista_puntos[componentes[i].lista_puntos.Count - 1].p.Y, 0);
                Dibujar_r(p1, p2);
            }
            if (componentes[i].Tipo == 2) {
                double[] azimuts = new double[2];
                azimuts = azimut_e_s(componentes[i]);
                if (componentes[i].direccion == EjeDeTrazado.puntosDelEje.EjeTrazado.sentidoCurva.Horario) {
                    Dibujar_c(componentes[i].xc, componentes[i].yc, componentes[i].radio, azimuts[1] + 90, azimuts[0] + 90);
                } else {
                    Dibujar_c(componentes[i].xc, componentes[i].yc, componentes[i].radio, azimuts[0] - 90, azimuts[1] - 90);
                }

            }
        }
        /// <summary>
        /// Dibuja todas las componentes curvas y rectas
        /// </summary>
        /// <param name="apartado">paso en el que nos encontramos</param>
        public void Dibujar_entidades(int apartado) {
            for (int i = 0; i < componentes.Count; i++) {
                if (componentes[i].Tipo == 1) {
                    tadLayShare.puntos.Punto3d p1 = new Punto3d(componentes[i].lista_puntos[0].p.X, componentes[i].lista_puntos[0].p.Y, 0);
                    tadLayShare.puntos.Punto3d p2 = new Punto3d(componentes[i].lista_puntos[componentes[i].lista_puntos.Count - 1].p.X, componentes[i].lista_puntos[componentes[i].lista_puntos.Count - 1].p.Y, 0);
                    Dibujar_r(p1, p2, apartado);
                }
                if (componentes[i].Tipo == 2) {
                    double[] azimuts = new double[2];
                    azimuts = azimut_e_s(componentes[i]);

                    if (componentes[i].direccion == EjeDeTrazado.puntosDelEje.EjeTrazado.sentidoCurva.Horario) {
                        if (componentes[i].curva_creada2==true)
                        {
                            if (componentes[i].radio>1214 && componentes[i].radio < 1215)
                            {

                            }
                            if (componentes[i].radio > 1527 && componentes[i].radio < 1528)
                            {

                            }
                            apartado = apartado + 20;
                            if (azimuts[0] > azimuts[1])
                            {
                                Dibujar_c(componentes[i].xc, componentes[i].yc, componentes[i].radio,  azimuts[0] + 90, azimuts[1] + 90, apartado);
                            }
                            else
                            {
                                Dibujar_c(componentes[i].xc, componentes[i].yc, componentes[i].radio, azimuts[1] + 90, azimuts[0] + 90, apartado);
                            }
                        }
                        else
                        {
                            Dibujar_c(componentes[i].xc, componentes[i].yc, componentes[i].radio, azimuts[1] + 90, azimuts[0] + 90, apartado);
                        }
                        
                        if (componentes[i].curva_creada2 == true)
                        {
                            apartado = apartado - 20;
                        }

                    } else {
                        if (componentes[i].curva_creada2 == true)
                        {
                            apartado = apartado + 20;
                            if (azimuts[0]< azimuts[1])
                            {
                                Dibujar_c(componentes[i].xc, componentes[i].yc, componentes[i].radio,  azimuts[1] - 90, azimuts[0] - 90, apartado);
                            }
                            else
                            {
                                Dibujar_c(componentes[i].xc, componentes[i].yc, componentes[i].radio, azimuts[0] - 90, azimuts[1] - 90, apartado);
                            }
                        }
                        else
                        {
                            Dibujar_c(componentes[i].xc, componentes[i].yc, componentes[i].radio, azimuts[0] - 90, azimuts[1] - 90, apartado);
                        }
                        
                        if (componentes[i].curva_creada2 == true)
                        {
                            apartado = apartado - 20;
                        }
                    }

                }
            }
        }
        /// <summary>
        /// Dibuja el trazado, rotula y crea el informe
        /// </summary>
        /// <param name="rotulacion">porcentaje del tamaño de la rotulación</param>
        /// <param name="rotu">true para rotular el trazado y false para no hacerlo</param>
        public void Dibujar_Todo(double rotulacion,bool rotu,List<Point2d> Lista_original_2d) {

            using (DocumentLock myDockLock = oCadManager.thisEditor.Document.LockDocument()) {

                //using (oSolucion miSolucion = new oSolucion(iIdSolucion))
                //{


                using (Transaction tr = oCadManager.StartTransaction()) {
                    BlockTable bt = (BlockTable)tr.GetObject(oCadManager.thisBase.BlockTableId, OpenMode.ForRead, false);
                    BlockTableRecord btr = (BlockTableRecord)tr.GetObject(bt[BlockTableRecord.ModelSpace], OpenMode.ForWrite, false);

                    double miBombeo = 2;

                    Polyline miEje = new Polyline();
                    int index = 0;
                    foreach (var componente in mcomponenetes) {
                        foreach (var componentPoint in componente.getComponentPoints()) {
                            miEje.AddVertexAt(index, new Point2d(componentPoint[0], componentPoint[1]), 0, 0, 0);
                            index++;
                        }
                        //miEje.AddVertexAt(index, new Point2d(0, 0), 0, 0, 0);//comprobacion
                        //index++;
                    }
                    engCadNet.oLayer.addLayer("Trazado", 4, false);
                    miEje.Layer = "Trazado";

                    btr.AppendEntity(miEje);
                    tr.AddNewlyCreatedDBObject(miEje, true);

                    //oXdata.setXdata(miEje.ObjectId, "tadilEje", miSolucion.idSolucion.ToString());
                    //ObjectId miId = oSerializarEntidad.StoreObjectInExtensionDictionary("info", miEje, tr, miEjeMem, miEjeTrazadoTadil.GetType().FullName);



                    oCadManager.thisEditor.UpdateScreen();

                    //Info UI
                    //oTadil.data.UserInfo.procesoTerminadoConTiempo(miMedicion.Elapsed.TotalMinutes);

                    tr.Commit();
                }

                //}
            }
            DialogResult result = MessageBox.Show("¿Desea crear un archivo de errores del trazado?\nNOTA: si el trazado es largo puede tardar varias minutos.", "Error de trazado", MessageBoxButtons.YesNo);
            if (result == DialogResult.Yes)
            {
                Distancia_Puntos_Resultado(mcomponenetes, Lista_original_2d);
            }

            if (rotu)
            {
                MessageBox.Show("Rotulando");
                Set_Pks();
                engCadNet.oLayer.addLayer("Rotulacion-Curva", 1, false);
                engCadNet.oLayer.addLayer("Rotulacion-Recta", 2, false);
                engCadNet.oLayer.addLayer("Rotulacion-Clotoide", 3, false);
                engCadNet.oLayer.addLayer("Rotulacion-Curva-100", 7, false);
                engCadNet.oLayer.addLayer("Rotulacion-Recta-100", 7, false);
                engCadNet.oLayer.addLayer("Rotulacion-Clotoide-100", 7, false);
                engCadNet.oLayer.addLayer("Rotulacion-Curva_inicial", 1, false);
                engCadNet.oLayer.addLayer("Rotulacion-Curva_final", 1, false);
                engCadNet.oLayer.addLayer("Rotulacion-Recta_inicial", 2, false);
                engCadNet.oLayer.addLayer("Rotulacion-Recta_final", 2, false);
                engCadNet.oLayer.addLayer("Rotulacion-Clotoide_inicial", 3, false);

                engCadNet.oLayer.addLayer("Rotulacion-singular", 7, false);
                double az = 0;
                List<double[]> componentPoint_ant = new List<double[]>();
                componentPoint_ant.Add(new double[] { 0, 0 });
                int contador = 0;
                double distancia = 0;
                bool primerpunto = true;
                Rotular r = new Rotular(rotulacion);
                int i = 0;
                var componente_ant = mcomponenetes[0];
                foreach (var componente in mcomponenetes)
                {
                    if (i > 0)
                    {
                        r.Dibujar_Singulares(componente, componente_ant);
                    }
                    else
                    {
                        r.Dibujar_Singulares(componente);
                    }

                    i++;
                    componente_ant = componente;
                }
               
                
                

                componentPoint_ant = new List<double[]>();
                componentPoint_ant.Add(new double[] { 0, 0 });
                contador = 0;
                distancia = 0;
                primerpunto = true;
                i = 0;
                componente_ant = mcomponenetes[0];
                foreach (var componente in mcomponenetes)
                {
                    if (i > 0)
                    {
                        r.Dibujar_Transversales(componente);
                    }
                    else
                    {
                        r.Dibujar_Transversales(componente);
                    }

                    i++;
                    componente_ant = componente;
                }
                r.Dibujar_Final(mcomponenetes[mcomponenetes.Count - 1]);
                EjeDeTrazado.InfoComponentes info = new EjeDeTrazado.InfoComponentes(mcomponenetes, new List<Vertice>(0));
                string nombre_informe = "";
                DialogResult resultinforme = MessageBox.Show("¿Desea crear un archivo del informe del trazado?", "Informe del trazado", MessageBoxButtons.YesNo);
                if (resultinforme == DialogResult.Yes)
                {

                    System.Windows.Forms.SaveFileDialog saveFileDialog1 = new System.Windows.Forms.SaveFileDialog();
                    saveFileDialog1.Title = "Fuardar informe del trazado";
                    saveFileDialog1.Filter = "csv files (*.csv)|*.csv|All files (*.*)|*.*";
                    saveFileDialog1.FilterIndex = 2;
                    saveFileDialog1.RestoreDirectory = true;
                    saveFileDialog1.DefaultExt = "csv";
                    if (saveFileDialog1.ShowDialog() == DialogResult.OK)
                    {
                        nombre_informe = saveFileDialog1.FileName;
                        List<EjeDeTrazado.oInformeEje> aa = info.escribirInforme(nombre_informe);
                    }
                    else
                    {
                    }
                }
                
            }

            

            

        }
        #region
        /*
         * 
         * Rotulacion
         * 
         */
        private void Prueba_rotulacion(EjeDeTrazado.InfoComponentes info, double dist, double dere, double izq, bool blanco, string iCapa)
        {
            short colorCurva;
            short colorClo;
            short colorLinea;
            if (blanco)
            {
                colorCurva = 0;
                colorClo = 0;
                colorLinea = 0;
            }
            else
            {
                colorCurva = 2;
                colorClo = 3;
                colorLinea = 1;
            }
            List<EjeDeTrazado.InfoComponente> misComponentes = info.getInfoComponentes;
            List<Entity> miLst = new List<Entity>();
            int i = 0;
            foreach (EjeDeTrazado.InfoComponente miInfoC in misComponentes)
            {


                if (miInfoC.getTipoComponente == EjeDeTrazado.componentes.Componente.tipoComponente.curva)
                {

                    while (i < miInfoC.getPkFinal - 0.1)
                    {
                        Polyline miLw1 = new Polyline();
                        double[] miPunto1 = { miInfoC.getPolilinea[i].coordenadaX, miInfoC.getPolilinea[i].coordenadaY};
                        double[] miPunto2 = { miInfoC.getPolilinea[i].coordenadaX, miInfoC.getPolilinea[i].coordenadaY };
                        double[] miPuntoIni = { miInfoC.getPolilinea[i].coordenadaX, miInfoC.getPolilinea[i].coordenadaY };
                        double miAzDer = 45;
                        // double[] miPunto1 = miInfoC.getPointLocation(i, dere, EjeTrazado.ladoCalzada.Derecha);
                        // double miAzDer = miEje.getAzimutTrans();
                        //double[] miPunto2 = miEje.getPointLocation(i, izq, EjeTrazado.ladoCalzada.Izquierda);
                        // double[] miPuntoIni = miEje.getPointAtDist(i);

                        Point2d miP1 = new Point2d(miPunto1[0], miPunto1[1]);
                        Point2d miP2 = new Point2d(miPunto2[0], miPunto2[1]);
                        Point2d miPIni = new Point2d(miPuntoIni[0], miPuntoIni[1]);
                        miLw1.AddVertexAt(0, miP1, 0, 0, 0);
                        miLw1.AddVertexAt(0, miPIni, 0, 0, 0);
                        miLw1.AddVertexAt(0, miP2, 0, 0, 0);
                        miLw1.Color = Color.FromColorIndex(ColorMethod.ByLayer, colorCurva);
                        miLst.Add(miLw1);


                        string miPk = getStringPK(i, dist);

                        oTexto.addText2D(miPk, miPunto1[0] + 3 * Math.Cos(miAzDer * Math.PI / 180), miPunto1[1] + 3 * Math.Sin(miAzDer * Math.PI / 180), 4, miAzDer * Math.PI / 180, colorCurva, iCapa);

                        i++;
                    }
                }
                else if (miInfoC.getTipoComponente == EjeDeTrazado.componentes.Componente.tipoComponente.linea)
                {

                    while (i < miInfoC.getPkFinal - 0.1)
                    {
                        Polyline miLw3 = new Polyline();
                        double[] miPunto1 = { miInfoC.getPolilinea[i].coordenadaX, miInfoC.getPolilinea[i].coordenadaY };
                        double[] miPunto2 = { miInfoC.getPolilinea[i].coordenadaX, miInfoC.getPolilinea[i].coordenadaY };
                        double[] miPuntoIni = { miInfoC.getPolilinea[i].coordenadaX, miInfoC.getPolilinea[i].coordenadaY };
                        double miAzDer = 45;
                        /*double[] miPunto1 = miEje.getPointLocation(i, dere, EjeTrazado.ladoCalzada.Derecha);
                        double miAzDer = miEje.getAzimutTrans();
                        double[] miPunto2 = miEje.getPointLocation(i, izq, EjeTrazado.ladoCalzada.Izquierda);
                        double[] miPuntoIni = miEje.getPointAtDist(i);*/
                        Point2d miP = new Point2d(miPunto1[0], miPunto1[1]);
                        Point2d miP2 = new Point2d(miPunto2[0], miPunto2[1]);
                        Point2d miPIni = new Point2d(miPuntoIni[0], miPuntoIni[1]);
                        miLw3.AddVertexAt(0, miP, 0, 0, 0);
                        miLw3.AddVertexAt(0, miPIni, 0, 0, 0);
                        miLw3.AddVertexAt(0, miP2, 0, 0, 0);
                        miLw3.Color = Color.FromColorIndex(ColorMethod.ByLayer, colorLinea);
                        miLst.Add(miLw3);

                        string miPk = getStringPK(i, dist);

                        oTexto.addText2D(miPk, miPunto1[0] + 3 * Math.Cos(miAzDer * Math.PI / 180), miPunto1[1] + 3 * Math.Sin(miAzDer * Math.PI / 180), 4, miAzDer * Math.PI / 180, colorLinea, iCapa);

                        i++;


                    }


                }
                else
                {

                    while (i < miInfoC.getPkFinal - 0.1)
                    {
                        Polyline miLw3 = new Polyline();
                        double[] miPunto1 = { miInfoC.getPolilinea[i].coordenadaX, miInfoC.getPolilinea[i].coordenadaY };
                        double[] miPunto2 = { miInfoC.getPolilinea[i].coordenadaX, miInfoC.getPolilinea[i].coordenadaY };
                        double[] miPuntoIni = { miInfoC.getPolilinea[i].coordenadaX, miInfoC.getPolilinea[i].coordenadaY };
                        double miAzDer = 45;
                        /*double[] miPunto1 = miEje.getPointLocation(i, dere, EjeTrazado.ladoCalzada.Derecha);
                        double miAzDer = miEje.getAzimutTrans();
                        double[] miPunto2 = miEje.getPointLocation(i, izq, EjeTrazado.ladoCalzada.Izquierda);*/
                        Point2d miP = new Point2d(miPunto1[0], miPunto1[1]);
                        Point2d miP2 = new Point2d(miPunto2[0], miPunto2[1]);
                        miLw3.AddVertexAt(0, miP, 0, 0, 0);
                        miLw3.AddVertexAt(0, miP2, 0, 0, 0);
                        miLw3.Color = Color.FromColorIndex(ColorMethod.ByLayer, colorClo);
                        miLst.Add(miLw3);

                        string miPk = getStringPK(i, dist);


                        oTexto.addText2D(miPk, miPunto1[0] + 3 * Math.Cos(miAzDer * Math.PI / 180), miPunto1[1] + 3 * Math.Sin(miAzDer * Math.PI / 180), 4, miAzDer * Math.PI / 180, colorClo, iCapa);

