            seno = Math.Sin((az + giro) * Math.PI / 180);
            coseno = Math.Cos((az + giro) * Math.PI / 180);

            x_p_2 = pm.X + dis * seno;
            y_p_2 = pm.Y + dis * coseno;

            x_p_1 = pm.X - dis * seno;
            y_p_1 = pm.Y - dis * coseno;


            tadLayShare.puntos.Punto3d p1 = new Punto3d(x_p_1, y_p_1, 0);
