            l.Add(new Punto(new Point2d(p2.coordenadaX, p2.coordenadaY)));

            return l;
        }
        private double Girar(Tuple<List<Punto>, double[], int> l, Componente c) {
            double r1 = Distancia_P_R(l.Item2[0], l.Item2[1], c.xc, c.yc);
