            double miLe;

            miLe = Math.Pow(miA, 2) / miRc;

            return miLe;
        }
        private double Get_R(Componente c) {

            Punto p = c.lista_puntos[1];
            Punto p_a = c.lista_puntos[1 - 1];
            Punto p_s = c.lista_puntos[1 + 1];
            p.a = Math.Pow(Math.Pow((p.p.X - p_a.p.X), 2) + Math.Pow((p.p.Y - p_a.p.Y), 2), 0.5);
            p.b = Math.Pow(Math.Pow((p_s.p.X - p.p.X), 2) + Math.Pow((p_s.p.Y - p.p.Y), 2), 0.5);
            p.c = Math.Pow(Math.Pow((p_s.p.X - p_a.p.X), 2) + Math.Pow((p_s.p.Y - p_a.p.Y), 2), 0.5);
            p.s = (p.a + p.b + p.c) / 2;
            p.R = (p.a * p.b * p.c) / (4 * Math.Pow(p.s * (p.s - p.a) * (p.s - p.b) * (p.s - p.c), 0.5));

            return p.R;
        }
        private Punto Rellenar_centro(Punto punto, double xc, double yc, int direccion) {
            Punto p, p_a;
            if (direccion == 1) {
                p = new Punto(new Point2d(punto.p.X, punto.p.Y));
                p_a = new Punto(new Point2d(xc, yc));
            } else {
                p_a = new Punto(new Point2d(punto.p.X, punto.p.Y));
                p = new Punto(new Point2d(xc, yc));
            }

            p.Dx = p.p.X - p_a.p.X;
            p.Dy = p.p.Y - p_a.p.Y;
            if (p.Dx == 0) {
                p.Ad1 = 0;
            } else {
                if (p.Dy == 0) {
                    p.Ad1 = 0;
                } else {
                    p.Ad1 = Math.Atan(p.Dy / p.Dx);
                }
            }
            p.Ad2 = p.Ad1 * (180 / Math.PI);

            if (p.Ad1 == 0) {
                p.signod = 0;
            } else {
                if (p.Ad1 < 0) {
                    p.signod = 1;
                } else {
                    p.signod = 2;
                }
            }

            if (p.Dx == 0) {
                p.signodx = 0;
            } else {
                if (p.Dx < 0) {
                    p.signodx = 1;
                } else {
                    p.signodx = 2;
                }
            }

            if (p.Dy == 0) {
                p.signody = 0;
            } else {
                if (p.Dy < 0) {
                    p.signody = 1;
                } else {
                    p.signody = 2;
                }
            }

            if (p.signod == 0) {
                p.Dc = 2;
            } else {
                p.Dc = 1;
            }
            if (p.Dc == 2) {
                if (p.Dy == 0) {
                    p.Orientacion = "E-W";
                } else {
                    p.Orientacion = "N-S";
                }
            }

            if (p.Dc == 2) {
                if (p.Orientacion == "E-W") {
                    if (p.Dx < 0) {
                        p.Azcardinal = 270;
                    } else {
                        p.Azcardinal = 90;
                    }
                } else {
                    if (p.Dy < 0) {
                        p.Azcardinal = 180;
                    } else {
                        p.Azcardinal = 0;
                    }
                }
            }

            //cuadrante
            if (p.Dc == 2) {
                p.cuadrante = 0;
            } else {
                if (p.Dx > 0 && p.Dy > 0) {
                    p.cuadrante = 1;
                } else {
                    if (p.Dx > 0 && p.Dy < 0) {
                        p.cuadrante = 2;
                    } else {
                        if (p.Dx < 0 && p.Dy < 0) {
                            p.cuadrante = 3;
                        } else {
                            p.cuadrante = 4;
                        }
                    }
                }
            }

            //Azimut
            if (p.Dc == 2) {
                p.Az = p.Azcardinal;
            } else {
                if (p.signod == 1) {
                    if (p.signodx == 2) {
                        p.Az = 90 - p.Ad2;

                    } else {
                        p.Az = 270 - p.Ad2;
                    }
                } else {
                    if (p.signodx == 2) {
                        p.Az = 90 - p.Ad2;

                    } else {
                        p.Az = 270 - p.Ad2;
                    }
                }
            }
            return p;
        }
