        /// <summary>
        /// Se encarga de dividir una polilinea si tiene muchos puntos
        /// </summary>
        /// <returns>
        /// Entero con el número de polilineas en las que se ha dividido
        /// </returns>
        public int Dividir_Polilinea()
        {
            
            int contador = 0;
            int pol=0;
            Listas_Polilineas.Add(new List<Punto>());
            for (int i=0;i<polilinea.Count;i++)
            {
                if (polilinea[i].secuenciagiro==1 && contador >2000)
                {
                    pol++;
                    contador = 0;
                    Listas_Polilineas.Add(new List<Punto>());
                }
                contador++;
                Listas_Polilineas[pol].Add(polilinea[i]);
            }
            return pol;
        }
