        public void Recorrido(List<Punto> poli) {
            int conta_curva = 0;

            for (int i = 1; i <= poli.Count - 2; i++) {
                if (i == 1 && poli[i - 1].Recta == 0 && poli[i].Recta == 0) {
                    lista.Add(i - 1);
                    conta_curva++;
                    minimos.Add(new List<int>());
                    maximos.Add(new List<int>());
                    recorrido.Add(new List<int>());
                    recorrido2.Add(new List<int>());
                    afines.Add(new List<int>());

                    minimos_p.Add(new List<int>());
                    maximos_p.Add(new List<int>());
                    recorrido_p.Add(new List<int>());
                    recorrido2_p.Add(new List<int>());
                    afines_p.Add(new List<int>());
                }
                if (poli[i - 1].Recta == 1 && poli[i].Recta == 0 && poli[i + 1].Recta == 0) {
                    lista.Add(i);
                    conta_curva++;
                    minimos.Add(new List<int>());
                    maximos.Add(new List<int>());
                    recorrido.Add(new List<int>());
                    recorrido2.Add(new List<int>());
                    afines.Add(new List<int>());

                    minimos_p.Add(new List<int>());
                    maximos_p.Add(new List<int>());
                    recorrido_p.Add(new List<int>());
                    recorrido2_p.Add(new List<int>());
                    afines_p.Add(new List<int>());
                }
                if (poli[i - 1].Recta == 0 && poli[i].Recta == 1 && poli[i + 1].Recta == 1) {
                    lista.Add(i - 1);

                }
            }

            int ini, fin, curva = 0, afin = 0;
            for (int r = 0; r < lista.Count; r++) {
                radios.Add(new List<double>());
                radios_p.Add(new List<double>());
                ini = lista[r];
                if (r + 1 < lista.Count) {
                    fin = lista[r + 1];
                } else {
                    fin = poli.Count - 1;
                }
                r++;
                for (int i = ini; i <= fin; i++) {
                    radios[curva].Add(poli[i].R);
                    radios_p[curva].Add(poli[i].Rp);
                }
                for (int i = 0; i <= fin - ini; i++) {

                    //R normal
                    minimos[curva].Add(-1);
                    maximos[curva].Add(-1);
                    for (int t = ini; t <= fin; t++) {

                        if (minimos[curva][i] == -1 && poli[t].Min_diferencia[i] != -1) {
                            minimos[curva][i] = poli[t].Min_diferencia[i];
                        }
                        if (poli[t].Min_diferencia[i] != -1) {
                            maximos[curva][i] = poli[t].Min_diferencia[i];
                            afin++;
                        }
                    }
                    recorrido[curva].Add(maximos[curva][i] - minimos[curva][i] + 1);
                    afines[curva].Add(afin);
                    recorrido2[curva].Add(recorrido[curva][i] * afines[curva][i]);
                    afin = 0;
                    //R prima
                    minimos_p[curva].Add(-1);
                    maximos_p[curva].Add(-1);
                    for (int t = ini; t <= fin; t++) {
                        if (minimos_p[curva][i] == -1 && poli[t].Min_diferencia_p[i] != -1) {
                            minimos_p[curva][i] = poli[t].Min_diferencia_p[i];
                        }
                        if (poli[t].Min_diferencia_p[i] != -1) {
                            maximos_p[curva][i] = poli[t].Min_diferencia_p[i];
                            afin++;
                        }
                    }
                    recorrido_p[curva].Add(maximos_p[curva][i] - minimos_p[curva][i] + 1);
                    afines_p[curva].Add(afin);
                    recorrido2_p[curva].Add(recorrido_p[curva][i] * afines_p[curva][i]);
                    afin = 0;
                }
                curva++;

            }
        }
        /// <summary>
        /// Crea las endidades curvas y rectas 
        /// </summary>
        /// <param name="t_med">tolerancia media introducida por el usuario</param>
        /// <param name="t_max">tolerancia máxima introducida por el usuario</param>
        /// <param name="n_curvas">número de curvas por tramo de giro</param>
        /// <param name="puntos_cluster">puntos minímos de un cluster</param>
        /// <param name="curva_g">curva de gran radio</param>
        public void Combinacion(double t_med, double t_max, int n_curvas,int puntos_cluster,double curva_g,bool dividir_curvas) {

            List<List<double>> radios_finales = new List<List<double>>();
            List<List<int>> minimo_final = new List<List<int>>();
            List<List<int>> maximo_final = new List<List<int>>();
            List<List<Point2d>> centros = new List<List<Point2d>>();
            List<Tuple<List<Punto>, double[], int>> Listas_rectas = new List<Tuple<List<Punto>, double[], int>>();//para rectas
            List<Tuple<List<double>, List<double>, List<double>, List<double>, int>> Listas_curvas = new List<Tuple<List<double>, List<double>, List<double>, List<double>, int>>();//para curvas /minimos cuadrados/xc/yc/R/posicion
            List<Tuple<List<double>, List<double>, List<double>, List<double>, int>> Listas_curvas_aux = new List<Tuple<List<double>, List<double>, List<double>, List<double>, int>>();//para curvas /minimos cuadrados/xc/yc/R/posicion

            bool puntos = false;
            bool puntos_p = false;
            for (int t = 0; t <= (lista.Count - 1) / 2; t++) {
                radios_finales.Add(new List<double>());
                minimo_final.Add(new List<int>());
                maximo_final.Add(new List<int>());
                int s_afines = 0, s_afines_p = 0;
                int s_recorrido = 0, s_recorrido_p = 0;
                for (int i = 0; i < afines[t].Count; i++) {
                    s_afines += afines[t][i];
                    s_afines_p += afines_p[t][i];
                    s_recorrido += recorrido[t][i];
                    s_recorrido_p += recorrido_p[t][i];
                }
                int s_afines_total = s_afines + s_afines_p;
                int s_recorrido_total = s_recorrido + s_recorrido_p;
                double s_afines_total2 = s_afines_total / (2 * afines[t].Count - 1);
                double s_recorrido_total2 = s_recorrido_total / (2 * afines[t].Count - 1);
                int poli_larga = puntos_cluster;
                puntos = false;
                puntos_p = false;

                for (int i = 0; i < afines[t].Count; i++) {
                    if ((afines[t][i] > s_afines_total2 && recorrido[t][i] > s_recorrido_total2 && recorrido[t][i] > 1)|| (afines[t][i] > poli_larga && recorrido[t][i] > poli_larga && recorrido[t][i] > 1)) {

                    } else {
                        if (afines[t].Count == 3 && i == 1) {
                            puntos = true;
                        } else {
                            if (afines[t].Count == 4 && (i == 1 || i == 2)) {
                                puntos = true;
                            } else {
                                puntos = false;
                                radios[t][i] = 0;
                                recorrido2[t][i] = 0;
                            }
                        }

                    }
                    if ((afines_p[t][i] > s_afines_total2 && recorrido_p[t][i] > s_recorrido_total2 && recorrido_p[t][i] > 1)|| (afines_p[t][i] > poli_larga && recorrido_p[t][i] > poli_larga && recorrido_p[t][i] > 1)) {

                    } else {
                        if (afines[t].Count == 5 && i == 2) {
                            puntos_p = true;
                        } else {
                            if (afines[t].Count == 5 && (i == 2 || i == 3)) {
                                puntos_p = true;
                            } else {
                                puntos_p = false;
                                radios_p[t][i] = 0;
                                recorrido2_p[t][i] = 0;
                            }
                        }

                    }
                    if (radios[t][i] == 0 && radios_p[t][i] == 0) {
                        radios_finales[t].Add(-1);
                        minimo_final[t].Add(-1);
                        maximo_final[t].Add(-1);
                    } else {
                        if (recorrido2[t][i] >= recorrido2_p[t][i]) {
                            if (double.IsInfinity(radios[t][i]) || double.IsNaN(radios[t][i])) {
                                radios_finales[t].Add(-1);
                            } else {
                                radios_finales[t].Add(radios[t][i]);
                            }

                            if (puntos) {
                                if ((minimos[t][i] - 1) < -1) {
                                    minimo_final[t].Add(-1);
                                    maximo_final[t].Add(-1);
                                } else {
                                    minimo_final[t].Add(minimos[t][i] - 1);
                                    maximo_final[t].Add(maximos[t][i] + 1);
                                }

                            } else {
                                if ((minimos[t][i] - 1) < -1) {
                                    minimo_final[t].Add(-1);
                                    maximo_final[t].Add(-1);
                                } else {
                                    minimo_final[t].Add(minimos[t][i]);
                                    maximo_final[t].Add(maximos[t][i]);
                                }
                            }

                        } else {
                            if (double.IsInfinity(radios_p[t][i]) || double.IsNaN(radios_p[t][i])) {
