                    }
                    else if (componentes[0].Tipo == 2 && componentes[1].Tipo == 1 && componentes[2].Tipo == 2)//curva--recta--curva
                    {
                        if (componentes[2].radio>gran_r)
                        {
                            intermedias = 1;
