                    for (int i = 0; i < componentes.Count - 1; i++)
                    {
                        if (componentes[i].caso7_e == true)
                        {
                            modificar = Resolver_caso7(i);
                            if (i >= 0 && i <= componentes.Count - 1)
                            {
                                componentes[i].solape += 1;
                            }
                            else
                            {

                            }
                        }
                    }
                }
            }
        }
        /*
         * este es el metodo utilizado en tadil que se utiliza cuando no hay margen de giro de las rectas
         */
        private List<object> Crear_CurvaNoPaso(Componente c1, Componente c2, Componente c3) {
            //ec de la primera recta
            double a_x0 = c1.lista_puntos[0].p.X;
            double a_y0 = c1.lista_puntos[0].p.Y;
            double b_x1 = c1.lista_puntos[1].p.X;
            double b_y1 = c1.lista_puntos[1].p.Y;

            double a_1 = (a_y0 - b_y1) / (a_x0 - b_x1);
            double b_1 = -b_x1 * (a_y0 - b_y1) / (a_x0 - b_x1) + b_y1;

            double c_x0 = c3.lista_puntos[0].p.X;
            double c_y0 = c3.lista_puntos[0].p.Y;
            double d_x1 = c3.lista_puntos[1].p.X;
            double d_y1 = c3.lista_puntos[1].p.Y;

            double c_1 = (c_y0 - d_y1) / (c_x0 - d_x1);
            double d_1 = -d_x1 * ((c_y0 - d_y1) / (c_x0 - d_x1)) + d_y1;

            double i_x = (d_1 - b_1) / (a_1 - c_1);
            double i_y = a_1 * ((d_1 - b_1) / (a_1 - c_1)) + b_1;
            Punto3d p_vertice = new Punto3d(i_x, i_y, 0);

            Punto p_raux = new Punto();
            Punto3d p1 = new Punto3d(c3.lista_puntos[c3.lista_puntos.Count - 2].p.X, c3.lista_puntos[c3.lista_puntos.Count - 2].p.Y, 0);
            Punto3d p2 = new Punto3d(c3.lista_puntos[c3.lista_puntos.Count - 1].p.X, c3.lista_puntos[c3.lista_puntos.Count - 1].p.Y, 0);
            double xc = c3.lista_puntos[c3.lista_puntos.Count - 2].p.X;
            double yc = c3.lista_puntos[c3.lista_puntos.Count - 2].p.Y;

            bool solape = true;

            List<object> entidades = new List<object>();
            while (solape) {
                solape = false;
                Punto3d[] puntosSing = addCurvaNoPaso(c2.radio, c1.azr, c3.azr, p_vertice, getSentidoCurva(c1.azr, c3.azr), false);
                mcomponenetes.Add(new Clotoide(puntosSing[0], puntosSing[1], c2.radio, 0, getSentidoCurva(c1.azr, c3.azr), 0, 0, true, EjeDeTrazado.puntosDelEje.EjeTrazado.tipoClotoide.entrada, c1.azr, false, getDelta(c1.azr, c3.azr), false, 0));

                mcomponenetes.Add(new Curva(puntosSing[1], puntosSing[2], puntosSing[4], c2.radio, mcomponenetes[mcomponenetes.Count - 1].getPkFinal(), 0, getSentidoCurva(c1.azr, c3.azr)));

                double[] miPuntoMedio = this.getPointAtDist(mcomponenetes.ElementAt(mcomponenetes.Count - 1).getPkIni + (mcomponenetes.ElementAt(mcomponenetes.Count - 1).getPkFinal() - mcomponenetes.ElementAt(mcomponenetes.Count - 1).getPkIni) / 2);

                mcomponenetes.Add(new Clotoide(puntosSing[2], puntosSing[3], c2.radio, mcomponenetes[mcomponenetes.Count - 1].getPkFinal(), getSentidoCurva(c1.azr, c3.azr), 0, 0, false, EjeDeTrazado.puntosDelEje.EjeTrazado.tipoClotoide.salida, c3.azr, false, getDelta(c1.azr, c3.azr), false, 0));
                Clotoide miClo1 = (Clotoide)mcomponenetes.ElementAt(mcomponenetes.Count - 1);
                double miQe1 = miClo1.getQe();


                Clotoide miClo2 = (Clotoide)mcomponenetes.ElementAt(mcomponenetes.Count - 3);
                double miQe2 = miClo2.getQe();

                Punto3d punto_medio = new Punto3d(miPuntoMedio[0], miPuntoMedio[1], 0);

                if (this.isSolapeS(puntosSing[4], puntosSing[1], puntosSing[2], punto_medio, miQe1, miQe2)) {
                    c2.radio = c2.radio * 110 / 100;
                    solape = true;
                    mcomponenetes.RemoveAt(mcomponenetes.Count - 1);
                    mcomponenetes.RemoveAt(mcomponenetes.Count - 1);
                    mcomponenetes.RemoveAt(mcomponenetes.Count - 1);
                } else {
                    entidades.Add(new Clotoide(puntosSing[0], puntosSing[1], c2.radio, 0, getSentidoCurva(c1.azr, c3.azr), 0, 0, true, EjeDeTrazado.puntosDelEje.EjeTrazado.tipoClotoide.entrada, c1.azr, false, getDelta(c1.azr, c3.azr), false, 0));
                    entidades.Add(new Curva(puntosSing[1], puntosSing[2], puntosSing[4], c2.radio, mcomponenetes[mcomponenetes.Count - 1].getPkFinal(), 0, getSentidoCurva(c1.azr, c3.azr)));
                    entidades.Add(new Clotoide(puntosSing[2], puntosSing[3], c2.radio, mcomponenetes[mcomponenetes.Count - 1].getPkFinal(), getSentidoCurva(c1.azr, c3.azr), 0, 0, false, EjeDeTrazado.puntosDelEje.EjeTrazado.tipoClotoide.salida, c3.azr, false, getDelta(c1.azr, c3.azr), false, 0));

                }
            }
            return entidades;
        }
