            double d2 = Distancia_P_R(l[0], l[1], componentes[i + 1].xc, componentes[i + 1].yc);
            if (d1 < componentes[i - 1].radio ||
                d2 < componentes[i + 1].radio)
            {
                if (componentes[i].creacion == 2)
