                        EjeDeTrazado.componentes.Clotoide Clo = Curva_Curva_M(componentes[componentes.Count - 2], componentes[componentes.Count - 1]);
                        //EjeDeTrazado.componentes.Clotoide Clo = Curva_Curva(componentes[componentes.Count - 2], componentes[componentes.Count - 1]);
                        if (Clo == null)
                        {
                            componentes[componentes.Count - 2].v_a_p = true;
                        }
                        else
                        {
                            if (Comprobar(Clo))
                            {
                                Dibujar_Clotoide(Clo);
                            }
                            else
                            {
                                componentes[componentes.Count - 2].v_a_p = true;

                            }
                        }
                    }
                }
                else if (componentes.Count == 3)
                {
                    if (componentes[componentes.Count - 2].Tipo == 2 && componentes[componentes.Count - 1].Tipo == 1)//si es curva--recta
                    {

                        int cont = 0;
                        EjeDeTrazado.componentes.Clotoide Clo = null;
                        while (cont < 1000)//el 1000 se pone para las comprobaciones
                        {
                            Rellenar_Recta(componentes[componentes.Count - 1]);
                            Rellenar_Curva(componentes[componentes.Count - 2]);
                            cont++;
                            Clo = Curva_Recta(componentes[componentes.Count - 2], componentes[componentes.Count - 1], 2);
                            if (Clo.getPuntoEntrada == Clo.getPuntoSalida || double.IsNaN(Clo.getQe()))
                            {
                                if (componentes[componentes.Count - 2].direccion == EjeTrazado.sentidoCurva.Antihorario)
                                {
                                    //Girar_Recta(componentes.Count - 1, Girar_acercar(componentes[componentes.Count - 1].lista_puntos, componentes[componentes.Count - 2], componentes[componentes.Count - 1].azr), componentes[componentes.Count - 1].azr);
                                    Girar_Recta(componentes.Count - 1, Girar_acercar(componentes[componentes.Count - 1].lista_puntos, componentes[componentes.Count - 2], componentes[componentes.Count - 1].azr), componentes[componentes.Count - 1].azr);

                                }
                                else
                                {
                                    //Girar_Recta(componentes.Count - 1, Girar_acercar(componentes[componentes.Count - 1].lista_puntos, componentes[componentes.Count - 2], componentes[componentes.Count - 1].azr), componentes[componentes.Count - 1].azr);
                                    Girar_Recta(componentes.Count - 1, Girar_acercar(componentes[componentes.Count - 1].lista_puntos, componentes[componentes.Count - 2], componentes[componentes.Count - 1].azr), componentes[componentes.Count - 1].azr);

                                }
                                //Dibujar_entidad(componentes.Count - 1);
                            }
                            else
                            {
                                if (((componentes[componentes.Count - 1].lista_puntos[0].p.X < componentes[componentes.Count - 1].lista_puntos[1].p.X) && (Clo.getPointAtDist(Clo.getPkFinal())[0] <= componentes[componentes.Count - 1].lista_puntos[1].p.X)) ||
                                    ((componentes[componentes.Count - 1].lista_puntos[0].p.X > componentes[componentes.Count - 1].lista_puntos[1].p.X) && (Clo.getPointAtDist(Clo.getPkFinal())[0] >= componentes[componentes.Count - 1].lista_puntos[1].p.X)))
                                {
                                    Dibujar_Clotoide(Clo);
                                    break;
                                }
                                /*if ((componentes[componentes.Count - 1].lista_puntos[0].p.X < Clo.getPointAtDist(Clo.getPkFinal())[0] && Clo.getPointAtDist(Clo.getPkFinal())[0] < componentes[componentes.Count - 1].lista_puntos[1].p.X) || (componentes[componentes.Count - 1].lista_puntos[0].p.X > Clo.getPointAtDist(Clo.getPkFinal())[0] && Clo.getPointAtDist(Clo.getPkFinal())[0] > componentes[componentes.Count - 1].lista_puntos[1].p.X))
                                {
                                    Dibujar_Clotoide(Clo);
                                    break;
                                }*/
                                else
                                {
                                    if (componentes[componentes.Count - 2].direccion == EjeTrazado.sentidoCurva.Antihorario)
                                    {
                                        //Girar_Recta(componentes.Count - 1, Girar_acercar(componentes[componentes.Count - 1].lista_puntos, componentes[componentes.Count - 2], componentes[componentes.Count - 1].azr), componentes[componentes.Count - 1].azr);
                                        Girar_Recta(componentes.Count - 1, Girar_acercar(componentes[componentes.Count - 1].lista_puntos, componentes[componentes.Count - 2], componentes[componentes.Count - 1].azr), componentes[componentes.Count - 1].azr);
                                    }
                                    else
                                    {
                                        //Girar_Recta(componentes.Count - 1, Girar_acercar(componentes[componentes.Count - 1].lista_puntos, componentes[componentes.Count - 2], componentes[componentes.Count - 1].azr), componentes[componentes.Count - 1].azr);
                                        Girar_Recta(componentes.Count - 1, Girar_acercar(componentes[componentes.Count - 1].lista_puntos, componentes[componentes.Count - 2], componentes[componentes.Count - 1].azr), componentes[componentes.Count - 1].azr);
                                    }
                                    //Dibujar_entidad(componentes.Count - 1);
                                }

                            }
                        }
                        if (Clo != null)
                        {
                            Dibujar_Clotoide(Clo);
                        }

                    }
                    else if (componentes[componentes.Count - 2].Tipo == 2 && componentes[componentes.Count - 1].Tipo == 2)//curva--curva
                    {
                        Rellenar_Curva(componentes[componentes.Count - 2]);
                        Rellenar_Curva(componentes[componentes.Count - 1]);
                        EjeDeTrazado.componentes.Clotoide Clo = Curva_Curva_M(componentes[componentes.Count - 2], componentes[componentes.Count - 1]);
                        //EjeDeTrazado.componentes.Clotoide Clo = Curva_Curva(componentes[componentes.Count - 2], componentes[componentes.Count - 1]);
                        if (Clo == null)
                        {
                            componentes[componentes.Count - 2].v_a_p = true;
                        }
                        else
                        {
                            if (Comprobar(Clo))
                            {
                                Dibujar_Clotoide(Clo);
                            }
                            else
                            {
                                componentes[componentes.Count - 2].v_a_p = true;
                            }
                        }
                    }
                }

                if (componentes.Count > 3)
                {
                    for (int i = intermedias; i < componentes.Count - 2; i++)
                    {
                        //se busca si una recta esta entre 2 curvas para crear una clotoide de entrada y otra de salida
                        if (componentes[i - 1].Tipo == 2 && componentes[i + 1].Tipo == 2 && componentes[i].Tipo == 1)
                        {
                            if (curva_gran_radio)
                            {
                                if (componentes[i].Tipo == 1 && componentes[i + 1].Tipo == 2)
                                {
                                    curva_gran_radio = false;
                                    EjeDeTrazado.componentes.Clotoide Clo = Recta_Curva(componentes[i], componentes[i + 1], 1);
                                    double[] pr = Clo.getPointAtDist(0);
                                    Dibujar_Clotoide(Clo);
                                }
                            }
                            else
                            {
                                //if (componentes[i].Tipo == 1 && componentes[i + 2].Tipo == 1 && (Math.Abs(componentes[i].azr - componentes[i + 2].azr) <= 2 || componentes[i + 1].radio > gran_r) && (componentes[i].creacion != 2 && componentes[i + 2].creacion != 2))
                                if (componentes[i].Tipo == 1 && componentes[i + 2].Tipo == 1 && (Math.Abs(componentes[i].azr - componentes[i + 2].azr) <= 2 || componentes[i + 1].radio > gran_r))
                                {
                                    EjeDeTrazado.componentes.Clotoide Clo = Curva_Recta(componentes[i - 1], componentes[i], 2);
                                    Dibujar_Clotoide(Clo);
                                    EjeDeTrazado.componentes.Curva Curva = Curva_Gran_Radio(componentes[i], componentes[i + 1], componentes[i + 2]);
                                    Dibujar_Curva(Curva);
                                    curva_gran_radio = true;
                                }
                                else
                                {
                                    EjeDeTrazado.componentes.Clotoide[] Clotoides = new EjeDeTrazado.componentes.Clotoide[2];
                                    Clotoides = Curva_Recta_Curva(componentes[i - 1], componentes[i], componentes[i + 1]);

                                    if (Clotoides[0] == null)
                                    {
                                        componentes[i - 1].v_m_g = true;
                                    }
                                    else
                                    {

                                        Dibujar_Clotoide(Clotoides[0]);
                                    }
                                    if (Clotoides[1] == null)
                                    {
                                        componentes[i + 1].v_m_g = true;
                                    }
                                    else
                                    {
                                        Dibujar_Clotoide(Clotoides[1]);
                                    }
                                }
                            }



                        }
                        if (componentes[i].Tipo == 2 && componentes[i + 1].Tipo == 2)
                        {
                            Rellenar_Curva(componentes[i]);
                            Rellenar_Curva(componentes[i + 1]);
                            EjeDeTrazado.componentes.Clotoide Clo = Curva_Curva_M(componentes[i], componentes[i + 1]);
                            //EjeDeTrazado.componentes.Clotoide Clo = Curva_Curva(componentes[i], componentes[i + 1]);
                            if (Clo == null)
                            {
                                componentes[i].v_a_p = true;
                            }
                            else
                            {
                                if (Comprobar(Clo))
                                {
                                    if (Clo.getTipo == EjeDeTrazado.puntosDelEje.EjeTrazado.tipoClotoide.salida)
                                    {
                                        Dibujar_Clotoide(Clo, 0, Clo.getLe_r());
                                    }
                                    else
                                    {
                                        Dibujar_Clotoide(Clo);
                                    }


                                }
                                else
                                {
                                    componentes[i].v_a_p = true;
                                }
                            }

                        }
                    }
                }
            }
            
        }

        public bool isComponentesVerificados() {
            bool hayDosRectasSeguidas = this.comprobarSiDosRectasSeguidas();
            bool hayDosCurvasSeguidasConDistintoSentido = this.comprobarSiDosCurvasSeguidasYDistintoSentido();
            return !hayDosRectasSeguidas || !hayDosCurvasSeguidasConDistintoSentido;
        }

        public VerificacionComponentesStatus obtenerEstadoVerificacionDeComponentes() {
            VerificacionComponentesStatus verificacionComponentesStatus = new VerificacionComponentesStatus();
            verificacionComponentesStatus.VerificacionDeCurvas = this.obtenerCurvasSeguidasyDistintoSentido();
            verificacionComponentesStatus.VerificacionDeRectas = this.obtenerRectasSeguidas();
            return verificacionComponentesStatus;
        }

        private bool comprobarSiDosCurvasSeguidasYDistintoSentido() {
            List<ComponentesCurvasSeguidasYDistintoSentido> componentesCurvasSeguidasYDistintoSentidos = this.obtenerCurvasSeguidasyDistintoSentido();
            return componentesCurvasSeguidasYDistintoSentidos.Any();  
        }

        private List<ComponentesCurvasSeguidasYDistintoSentido> obtenerCurvasSeguidasyDistintoSentido() {
            List<Componente> componentesCurvas = this.filtrarComponentesPorTipo(2);
            List<ComponentesCurvasSeguidasYDistintoSentido> componentesCurvasSeguidasYDistintoSentidos = new List<ComponentesCurvasSeguidasYDistintoSentido>();

            componentesCurvas.ForEach(componente1 => {
                int componenteCurvaIndex = this.componentes.IndexOf(componente1);
                int siguienteComponenteIndex = componenteCurvaIndex + 1;
                try {
                    Componente componente2 = this.componentes.ElementAt(siguienteComponenteIndex);
                    //si es del mismo tipo que el componente 1 y ademas la direccion es distinta
                    if (componente1.Tipo == componente2.Tipo) {
                        if (!componente1.direccion.Equals(componente2.direccion)) {
                            //error de verificacon
                            componentesCurvasSeguidasYDistintoSentidos.Add(new ComponentesCurvasSeguidasYDistintoSentido(componente1, componente2));
                        }
                    }
                } catch { }     
            });

            return componentesCurvasSeguidasYDistintoSentidos;
        }

        private bool comprobarSiDosRectasSeguidas() {
            List<ComponentesRectasSeguidas> rectasSeguidas = this.obtenerRectasSeguidas();
            return rectasSeguidas.Any();
        }

        private List<ComponentesRectasSeguidas> obtenerRectasSeguidas() {
            List<Componente> componentesRectas = this.filtrarComponentesPorTipo(1);
            List<ComponentesRectasSeguidas> rectasSeguidas = new List<ComponentesRectasSeguidas>();

            //Para cada componente recta encontrada se realiza la comprobacion de si el siguiente elemento
            //tambien es una recta
            componentesRectas.ForEach(componente1 =>
            {
                //indice del componente recta
                int componenteRectaIndex = this.componentes.IndexOf(componente1);
                //siguiente componente a la recta 
                int siguienteComponenteIndex = componenteRectaIndex + 1;

                try {
                    Componente componente2 = this.componentes.ElementAt(siguienteComponenteIndex);
                    if (componente1.Tipo == componente2.Tipo) {
                        rectasSeguidas.Add(new ComponentesRectasSeguidas(componente1, componente2));
                    }
                } catch { } 
            });

            return rectasSeguidas;
        }

        private List<Componente> filtrarComponentesPorTipo(int tipo) {
            return this.componentes.Where(componente => componente.Tipo == tipo).ToList();
        }

        public void addViabilidadListener(IViabilidadListener listener) {
            this.viabilidadListeners.Add(listener);
        }

        public void removeAllViabilidadListener() {
            this.viabilidadListeners.Clear();
        }
        private void Viabilidad_Clusterizacion(int comp)
        {
            Rellenar_Curva(componentes[comp]);
            if (comp>1 && comp<componentes.Count-2)
            {
                /*
                 * Para componentes anteiores
                 */
                if (componentes[comp-1].Tipo==1 && componentes[comp - 1].creacion!=2)
                {
                    if (componentes[comp].direccion!= componentes[comp-2].direccion)
                    {
                        double[] lr;
                        lr = ajuste_recta(componentes[comp - 1].lista_puntos, 0).Item2;
                        double dis = Distancia_P_R(lr[0], lr[1], componentes[comp].xc, componentes[comp].yc);

                        double dis2 = Distancia_P_R(lr[0], lr[1], componentes[comp - 2].xc, componentes[comp - 2].yc);
                        if (dis < componentes[comp].radio && dis2 > componentes[comp - 2].radio)
                        {
                            while (dis < componentes[comp].radio && dis2 > componentes[comp - 2].radio)
                            {
                                if (componentes[comp].direccion == EjeDeTrazado.puntosDelEje.EjeTrazado.sentidoCurva.Antihorario)
                                {
                                    Girar_Recta(comp - 1, 0.01, componentes[comp - 1].azr);
                                }
                                else
                                {
                                    Girar_Recta(comp - 1, -0.01, componentes[comp - 1].azr);
                                }
                                Rellenar_Recta(componentes[comp - 1]);
                                lr = ajuste_recta(componentes[comp - 1].lista_puntos, 0).Item2;
                                dis = Distancia_P_R(lr[0], lr[1], componentes[comp].xc, componentes[comp].yc);

                                dis2 = Distancia_P_R(lr[0], lr[1], componentes[comp - 2].xc, componentes[comp - 2].yc);
                            }
                        }
                    }
                }
                /*
                 * Para componentes posteriores
                 */
                if (componentes[comp + 1].Tipo == 1 && componentes[comp + 1].creacion != 2)
                {
                    if (componentes[comp].direccion != componentes[comp + 2].direccion)
                    {
                        double[] lr;
                        lr = ajuste_recta(componentes[comp + 1].lista_puntos, 0).Item2;
                        double dis = Distancia_P_R(lr[0], lr[1], componentes[comp].xc, componentes[comp].yc);

                        double dis2 = Distancia_P_R(lr[0], lr[1], componentes[comp + 2].xc, componentes[comp - 2].yc);
                        if (dis < componentes[comp].radio && dis2 > componentes[comp + 2].radio)
                        {
                            while (dis < componentes[comp].radio && dis2 > componentes[comp + 2].radio)
                            {
                                if (componentes[comp].direccion == EjeDeTrazado.puntosDelEje.EjeTrazado.sentidoCurva.Antihorario)
                                {
                                    Girar_Recta(comp + 1, 0.01, componentes[comp + 1].azr);
                                }
                                else
                                {
                                    Girar_Recta(comp + 1, -0.01, componentes[comp + 1].azr);
                                }
                                Rellenar_Recta(componentes[comp+1]);
                                lr = ajuste_recta(componentes[comp + 1].lista_puntos, 0).Item2;
                                dis = Distancia_P_R(lr[0], lr[1], componentes[comp].xc, componentes[comp].yc);

                                dis2 = Distancia_P_R(lr[0], lr[1], componentes[comp + 2].xc, componentes[comp - 2].yc);
                            }
                        }
                    }
                }
            }
        }
        /// <summary>
        /// Une todas las componentes si se ha tenido que dividir la polilinea
        /// </summary>
        public void Unir_Componentes()
        {
            componentes.Clear();
            foreach (Componente c in componentes_temp)
            {
                componentes.Add(c);
            }
            List<Punto> lista_aux = new List<Punto>();
            for (int i=0;i<= Listas_Polilineas.Count-1;i++)
            {
                for (int t = 0; t <= Listas_Polilineas[i].Count - 1; t++)
                {
                    lista_aux.Add(new Punto(Listas_Polilineas[i][t]));
                }
            }

            for (int i = 0; i < lista_aux.Count - 1; i++)
            {
                if (Iguales(lista_aux[i], lista_aux[i + 1]))
                {
                    lista_aux.RemoveAt(i);
                }
            }
            polilinea = lista_aux;
            //eliminas las rectas dentro de curvas
            Recta_Dentro_Curva();
        }
        /*
         *  eliminas las rectas dentro de curvas
         */
        public void Recta_Dentro_Curva()
        {
            for (int i=0;i<componentes.Count;i++)
            {
                for (int t = 0; t < componentes.Count; t++)
                {
                    if (componentes[i].Tipo==1)
                    {
                        if (componentes[i].ini > componentes[t].ini && componentes[i].ini < componentes[t].fin)
                        {
                            componentes.RemoveAt(i);
                            i--;
                            break;
                        }
                        if (componentes[i].fin > componentes[t].ini && componentes[i].fin < componentes[t].fin)
                        {
                            componentes.RemoveAt(i);
                            i--;
                            break;
                        }
                    }
                    
                }
            }
        }
        public void Eliminar_Curva(int i)
        {
            if (i == 0 || i == componentes.Count - 1)
            {
                if (i==0)
                {
                    Componentes.RemoveAt(i+1);
                }
                else
                {
                    Componentes.RemoveAt(i);
                }
            }
            else
            {
                double[] azs = azimut_e_s(componentes[i]);
                double[] azs2 = azimut_e_s(componentes[i + 1]);
                double c_az, c_az2;
                if (componentes[i].direccion == EjeDeTrazado.puntosDelEje.EjeTrazado.sentidoCurva.Horario)
                {
                    if (azs[0] < azs[1])
                    {
                        c_az = azs[1] - azs[0];
                    }
                    else
                    {
                        c_az = azs[1] + (360 - azs[0]);
                    }
                }
                else
                {
                    if (azs[0] > azs[1])
                    {
                        c_az = azs[0] - azs[1];
                    }
                    else
                    {
                        c_az = azs[0] + (360 - azs[1]);
                    }
                }
                if (componentes[i + 1].direccion == EjeDeTrazado.puntosDelEje.EjeTrazado.sentidoCurva.Horario)
                {
                    if (azs2[0] < azs2[1])
                    {
                        c_az2 = azs2[1] - azs2[0];
                    }
                    else
                    {
                        c_az2 = azs2[1] + (360 - azs2[0]);
                    }
                }
                else
                {
                    if (azs2[0] > azs2[1])
                    {
                        c_az2 = azs2[0] - azs2[1];
                    }
                    else
                    {
                        c_az2 = azs2[0] + (360 - azs2[1]);
                    }
                }
                if (c_az > c_az2)
                {
                    componentes.RemoveAt(i + 1);
                    if (componentes[i+1].Tipo==1 && componentes[i+1].creacion==2)
                    {
                        componentes.RemoveAt(i + 1);
                    }
                    if (componentes[i].Tipo == 1 && componentes[i].creacion == 2)
                    {
                        componentes.RemoveAt(i);
                    }
                }
                else
                {
                    componentes.RemoveAt(i);
                    if (componentes[i].Tipo == 1 && componentes[i].creacion == 2)
                    {
                        componentes.RemoveAt(i);
                    }
                    if (componentes[i-1].Tipo == 1 && componentes[i-1].creacion == 2)
                    {
                        componentes.RemoveAt(i-1);
                    }
                }
            }
        }
        public void curvas_iguales()
        {
            for (int i=0;i<componentes.Count;i++)
            {
                for (int r=0; r < componentes.Count;r++)
                {
                    if (i!=r)
                    {
                        if (componentes[i].ini== componentes[r].ini && componentes[i].fin == componentes[r].fin)
                        {
                            componentes.RemoveAt(r);
                        }
                    }
                }
            }
        }
        public double Dif_az(int i)
        {
            if (componentes[i].direccion== EjeDeTrazado.puntosDelEje.EjeTrazado.sentidoCurva.Horario)
            {
                if (componentes[i].azte< componentes[i].azts)
                {
                    return componentes[i].azts - componentes[i].azte;
                }
                else
                {
                    return 360-componentes[i].azte+ componentes[i].azts;
                }
            }
            else
            {
                if (componentes[i].azte > componentes[i].azts)
                {
                    return componentes[i].azte - componentes[i].azts;
                }
                else
                {
                    return 360 - componentes[i].azts + componentes[i].azte;
                }
            }
        }
        public void Eliminar_Clotoides()
        {
            Rellenar_Componentes();
            double az1, az2, az3;
            for (int i=1;i<componentes.Count;i++)
            {
                if (componentes[i].cluster == false)
                {
                    if (componentes[i - 1].Tipo == 2 && componentes[i].Tipo == 2 && componentes[i + 1].Tipo == 2 &&
                    componentes[i - 1].direccion == componentes[i].direccion && componentes[i].direccion == componentes[i + 1].direccion)
                    {
                        if ((componentes[i - 1].radio < componentes[i].radio && componentes[i].radio < componentes[i + 1].radio) ||
                            (componentes[i - 1].radio > componentes[i].radio && componentes[i].radio > componentes[i + 1].radio))
                        {
                            if ((componentes[i - 1].azts < componentes[i].azte && componentes[i].azte < componentes[i + 1].azte) ||
                                (componentes[i - 1].azts > componentes[i].azte && componentes[i].azte > componentes[i + 1].azte))
                            {
                                if ((componentes[i - 1].azts < componentes[i].azts && componentes[i].azts < componentes[i + 1].azte) ||
                                    (componentes[i - 1].azts > componentes[i].azts && componentes[i].azts > componentes[i + 1].azte))
                                {
                                    az1 = Dif_az(i - 1);
                                    az2 = Dif_az(i);
                                    az3 = Dif_az(i + 1);
                                    //if (az2<az1 && az2<az3)
                                    //{
                                        //componentes.RemoveAt(i);
                                        //i--;
                                    //}
                                }
                            }
                        }
                    }
                }
            }
        }
        /*
         * Se rellena el valor inicial de las componentes para comprar posteriormente con sus modificaciones
         */
        public void Valor_Inicial_Componentes()
        {
            for (int i=0;i<componentes.Count;i++)
            {
                Componente c = new Componente();
                componentes[i].radio_i = componentes[i].radio;
                componentes[i].xc_i = componentes[i].xc;
                componentes[i].yc_i = componentes[i].yc;
                componentes[i].dif_az_i = Dif_az(i);
                foreach (Punto p in componentes[i].lista_puntos)
                {
                    componentes[i].add_i(p);
                }
                componentes[i].L_Arco_i= componentes[i].radio_i*(componentes[i].dif_az_i*Math.PI/180);
            }
        }

