        public double[] Vertice_rectas(Componente c1 ,Componente c3)
        {
            double[] vertice = new double[2];
            double a_x0 = c1.lista_puntos[0].p.X;
            double a_y0 = c1.lista_puntos[0].p.Y;
            double b_x1 = c1.lista_puntos[c1.lista_puntos.Count-1].p.X;
            double b_y1 = c1.lista_puntos[c1.lista_puntos.Count - 1].p.Y;

            double a_1 = (a_y0 - b_y1) / (a_x0 - b_x1);
            double b_1 = -b_x1 * (a_y0 - b_y1) / (a_x0 - b_x1) + b_y1;

            double c_x0 = c3.lista_puntos[0].p.X;
            double c_y0 = c3.lista_puntos[0].p.Y;
            double d_x1 = c3.lista_puntos[c3.lista_puntos.Count - 1].p.X;
            double d_y1 = c3.lista_puntos[c3.lista_puntos.Count - 1].p.Y;

            double c_1 = (c_y0 - d_y1) / (c_x0 - d_x1);
            double d_1 = -d_x1 * ((c_y0 - d_y1) / (c_x0 - d_x1)) + d_y1;

            double i_x = (d_1 - b_1) / (a_1 - c_1);
            double i_y = a_1 * ((d_1 - b_1) / (a_1 - c_1)) + b_1;
            vertice[0] = i_x;
            vertice[1] = i_y;
            return vertice;

        }
        public void Aniadir_Rectar_Radio_Grande()
        {
            int contador;
            bool contar = true;
            List<Componente> lista_rectas_aniadir = new List<Componente>();
            for (int i=0;i<componentes.Count-1;i++)
            {
                lista_rectas_aniadir = new List<Componente>();
                contar = true;
                for (int t = componentes[i].fin + 1; t < componentes[i + 1].ini; t++)
                {
                    if (polilinea[t].secuenciagiro==1)
                    {
                        contar = false;
                    }
                }
                if (contar && componentes[i + 1].ini-(componentes[i].fin+1)>1)
                {
                    contador = 0;
                    for (int t = componentes[i].fin + 1; t < componentes[i + 1].ini; t++)
                    {
                        if (polilinea[t].R > 10000)
                        {
                            contador++;
                        }
                        else
                        {
                            if (contador > 1)
                            {

                                lista_rectas_aniadir.Add(new Componente(new Punto(new Point2d(polilinea[t - contador].p.X, polilinea[t - contador].p.Y)), 1));
                                for (int r = t - contador + 1; r < t; r++)
                                {

                                    lista_rectas_aniadir[lista_rectas_aniadir.Count - 1].add(new Punto(new Point2d(polilinea[r].p.X, polilinea[r].p.Y)));
                                }


                            }
                            contador = 0;
                        }
                    }
                    if (contador > 1)
                    {
                        lista_rectas_aniadir.Add(new Componente(new Punto(new Point2d(polilinea[componentes[i + 1].ini - contador].p.X, polilinea[componentes[i + 1].ini - contador].p.Y)), 1));
                        for (int r = componentes[i + 1].ini - contador+1; r < componentes[i + 1].ini; r++)
                        {

                            lista_rectas_aniadir[lista_rectas_aniadir.Count - 1].add(new Punto(new Point2d(polilinea[r].p.X, polilinea[r].p.Y)));
                        }

                    }
                    contador = 0;
                }
                for (int t=0;t< lista_rectas_aniadir.Count;t++)
                {
                    componentes.Insert(i+1+t, lista_rectas_aniadir[t]);
                }
                i += lista_rectas_aniadir.Count;

            }
        }
        public int Crear_Sublistas()
        {
            int pol = 0;
            componentes_general.Add(new List<Componente>());
            for (int i = 0; i < componentes.Count; i++)
            {
                if (componentes[i].curva_creada)
                {
                    if (i>0 && i<componentes.Count-1)
                    {
                        if (componentes[i - 1].Tipo == 1 && componentes[i + 1].Tipo == 1 && Math.Abs(componentes[i - 1].azr- componentes[i + 1].azr) <2)
                        {
                            componentes_general[pol].Add(componentes[i]);
                        }
                        else
                        {
                            pol++;
                            componentes_general.Add(new List<Componente>());
                        }
                    }
                    else
                    {
                        pol++;
                        componentes_general.Add(new List<Componente>());
                    }
                    
                }
                else
                {
                    componentes_general[pol].Add(componentes[i]);
                }
            }
            return pol;
        }
