                    if (distancia_g > distancia)
                    {
                        punto_p_o = Polilinea2d[t].Item2;
                        distancia_g = distancia;
                    }

                }
                distancias.Add(distancia_g);

            }
            Informe(Polilinea_original, distancias);
        }


        /// <summary>
        /// Crea una polilinea cuyos tramos no tienen mas de 1 metros
        /// </summary>
        /// <param name="polilinea">polilinea original a dividir</param>
        /// <returns>polilinea ya dividida</returns>
        private List<Point2d> Dividir_Segmentos_Largos(List<Point2d> polilinea)
        {
            List<Point2d> polilinea_temp = new List<Point2d>();
            List<Point2d> segmento = new List<Point2d>();
            Point2d p1 = new Point2d();
            Point2d p2 = new Point2d();
            int partes = 1;
            for (int i = 0; i < polilinea.Count - 1; i++)
            {
                p1 = new Point2d(polilinea[i].X, polilinea[i].Y);
                p2 = new Point2d(polilinea[i + 1].X, polilinea[i + 1].Y);
                if (Distancia(p1, p2) > 0.1)
                {
                    polilinea_temp.Add(polilinea[i]);
                    partes = (int)Math.Truncate(Distancia(p1, p2)*100);
                    if (partes > 1)
                    {
                        segmento = Dividir_Segmento(polilinea[i + 1], polilinea[i], partes);
                    }
                    else
                    {
                        segmento = Dividir_Segmento(polilinea[i + 1], polilinea[i], 2);
                    }
                    for (int t = 0; t < segmento.Count; t++)
                    {
                        polilinea_temp.Add(segmento[t]);
                    }
                }
                else
                {
                    polilinea_temp.Add(polilinea[i]);
                }
            }
            polilinea_temp.Add(polilinea[polilinea.Count - 1]);
            return polilinea_temp;
        }
        /// <summary>
        /// Divide un segmento
        /// </summary>
        /// <param name="p1">punto 1 del segmento</param>
        /// <param name="p2">punto 2 del segmento</param>
        /// <param name="partes">partes en las que dividimos el segmento</param>
        /// <returns>puntos intermedios del segmento ya dividido</returns>
        private List<Point2d> Dividir_Segmento(Point2d p1, Point2d p2, int partes)
        {
            List<Point2d> segmento = new List<Point2d>();
            double r;
            double x, y;


            for (int i = 1; i <= partes; i++)
            {
                r = ((double)partes - (double)i) / (double)i;
                x = (p1.X + r * p2.X) / (1 + r);
                y = (p1.Y + r * p2.Y) / (1 + r);
                if (segmento.Count == 0)
                {
                    segmento.Add(new Point2d(x, y));
                }
                else
                {
                    segmento.Add(new Point2d(x, y));
                }

            }
            return segmento;
        }
        /// <summary>
        /// Se elimina el error de un punto erroneo que se detecta a una distancia demasiado grande
        /// </summary>
        /// <param name="poli">polilinea a corregir</param>
        /// <returns>polilinea corregida</returns>
        private List<Tuple<Point2d, int>> Erroneos(List<Tuple<Point2d,int>> poli)
        {
            for (int i = 0; i < poli.Count - 2; i++)
            {
                if (Distancia(new Point2d(poli[i].Item1.X, poli[i].Item1.Y), new Point2d(poli[i + 1].Item1.X, poli[i + 1].Item1.Y)) > 100000 &&
                    Distancia(new Point2d(poli[i + 1].Item1.X, poli[i + 1].Item1.Y), new Point2d(poli[i + 2].Item1.X, poli[i + 2].Item1.Y)) > 100000)
                {
                    poli.RemoveAt(i + 1);
                }
            }
            return poli;
        }
        public void Informe(List<Point2d> lista,List<double> dis)
        {
            string nombre_informe = "";
            System.Windows.Forms.SaveFileDialog saveFileDialog1 = new System.Windows.Forms.SaveFileDialog();
            saveFileDialog1.Title = "Guardar informe de error de trazado";
            saveFileDialog1.Filter = "csv files (*.csv)|*.csv|All files (*.*)|*.*";
            saveFileDialog1.FilterIndex = 2;
            saveFileDialog1.RestoreDirectory = true;
            saveFileDialog1.DefaultExt = "csv";
            if (saveFileDialog1.ShowDialog() == DialogResult.OK)
            {
                nombre_informe = saveFileDialog1.FileName;
                System.IO.TextWriter output = new StreamWriter(nombre_informe, false, Encoding.BigEndianUnicode);
               
                output.WriteLine();
                output.WriteLine();
                output.WriteLine();
                output.WriteLine();
                output.Write(";");
                output.Write(";");
                output.Write("Punto");
                output.Write(";");
                output.Write("X");
                output.Write(";");
                output.Write("Y");
                output.Write(";");
                output.Write("Error");
                output.Write(";");
                output.WriteLine();
                for (int i=0;i< lista.Count && i < dis.Count; i++)
                {
                    output.Write(";");
                    output.Write(";");
                    output.Write(i+1);
                    output.Write(";");
                    output.Write(lista[i].X);
                    output.Write(";");
                    output.Write(lista[i].Y);
                    output.Write(";");
                    output.Write(dis[i]);
                    output.Write(";");
                    output.WriteLine();
                }

                output.Flush();
                output.Close();
            }
            else
            {
                MessageBox.Show("No se ha creado el informe.");
            }


        }
        /// <summary>
        /// Comprueba que se cumplan las tolerancias en rectas
        /// </summary>
        /// <param name="l"></param>
        /// <param name="tmax"></param>
        /// <param name="tmed"></param>
        /// <returns>true si lo cumple y false sino lo cumple</returns>
        public bool Comprobar_Tolerancia_Recta(List<Punto> l,double tmax,double tmed) 
        {
            double dis = Distancia(l[0].p,polilinea[0].p);
            
            int punto = 0;
            for (int i=1;i<polilinea.Count;i++)
            {
                if (dis>Distancia(l[0].p,polilinea[i].p))
                {
                    dis = Distancia(l[0].p, polilinea[i].p);
                    punto = i;
                }
            }

            double dis2 = Distancia(l[l.Count-1].p, polilinea[0].p);

            int punto2 = 0;
            for (int i = 1; i < polilinea.Count; i++)
            {
                if (dis2 > Distancia(l[l.Count - 1].p, polilinea[i].p))
                {
                    dis2 = Distancia(l[l.Count - 1].p, polilinea[i].p);
                    punto2 = i;
                }
            }
            List<double> maximos = new List<double>();
            double[] recta = new double[2];
            recta = ajuste_recta(l,0).Item2;
            double suma = 0;
            for (int i=punto;i<=punto2;i++)
            {
                maximos.Add(Distancia_P_R(recta[0],recta[1],polilinea[i].p.X, polilinea[i].p.Y));
                suma += Distancia_P_R(recta[0], recta[1], polilinea[i].p.X, polilinea[i].p.Y);
                if (tmax< Distancia_P_R(recta[0], recta[1], polilinea[i].p.X, polilinea[i].p.Y))
                {
                    
                    return false;
                }
            }

            double media = suma / maximos.Count;
            if (tmed<media)
            {
                
                return false;
            }

            return true;
        }
        public void Recta_curva_dividida()
        {
            for (int i=0;i<componentes.Count-1;i++)
            {
                if (componentes[i].Tipo==2 && componentes[i+1].Tipo == 2 && componentes[i].direccion== componentes[i+1].direccion)
                {
                    Crear_RECM_Divididas(i);
                    if (componentes[i+1].Tipo == 1 && double.IsNaN(componentes[i + 1].azr))
                    {
                        componentes.RemoveAt(i+1);
                    }
                }
            }
        }
        /// <summary>
        /// elimina los puntos que se encuentran a menor distancia que la que se pasa por parametro
        /// </summary>
        /// <param name="dis">distancia</param>
        public void Eliminar_Distancia(double dis)
        {
            int contador = 0;
            for (int i=0;i<polilinea.Count-1;i++)
            {
                if (Distancia(polilinea[i].p,polilinea[i+1].p)<dis)
                {
                    polilinea.RemoveAt(i+1);
                    i--;
                    contador++;
                }
            }
            MessageBox.Show("Se han eliminado "+ contador+ " puntos cercanos");
        }
        /// <summary>
        /// elimina los puntos que se encuentran a menor distancia que la que se pasa por parametro
        /// </summary>
        /// <param name="dis">distancia</param>
        public int Eliminar_Distancia_m(double dis)
        {
            int contador = 0;
            List<Punto> polilinea_aux = new List<Punto>();
            foreach (Punto p in polilinea)
            {
                polilinea_aux.Add(new Punto(p));
            }
            for (int i = 0; i < polilinea_aux.Count - 1; i++)
            {
                if (Distancia(polilinea_aux[i].p, polilinea_aux[i + 1].p) < dis)
                {
                    i--;
                    polilinea_aux.RemoveAt(i + 1);
                    contador++;
                }
            }
            return contador;
        }
        /// <summary>
        /// clusteriza 2 curvas
        /// </summary>
        /// <param name="i"></param>
        public void Clusterizar(int i)
        {
            List<Punto> lista = new List<Punto>();
            if (componentes[i].ini>0 && componentes[i+1].fin>0)
            {
                for (int r= componentes[i].ini;r< componentes[i+1].fin; r++)
                {
                    lista.Add(new Punto(polilinea[r].p));
                }
            }
            else
            {
                for (int r = 0; r <= componentes[i].lista_puntos.Count - 1; r++)
                {
                    lista.Add(new Punto(componentes[i].lista_puntos[r].p));
                }
                for (int r = 0; r <= componentes[i+1].lista_puntos.Count - 1; r++)
                {
                    lista.Add(new Punto(componentes[i+1].lista_puntos[r].p));
                }
            }
            Tuple<double, double, double> Curva = this.Clusterizacion(lista);
            Crear_Curva_2Puntos(lista[0], lista[lista.Count - 1], Curva.Item1, Curva.Item2, Curva.Item3, i);
            //Crear_Curva(componentes[i - 1].ini, componentes[i].fin, Curva.Item1, Curva.Item2, Curva.Item3, i - 1);
            componentes[i].direccion = componentes[i+1].direccion;
            componentes[i].Clusterizada = true;
            componentes.RemoveAt(i+1);
            componentes.RemoveAt(i+1);
        }
        public bool Comprobar_curva_nueva(Componente c1, Componente c2, double[] vert)
        {
            double x1 = c1.lista_puntos[0].p.X;
            double x2 = c1.lista_puntos[c1.lista_puntos.Count-1].p.X;
            double x3 = c2.lista_puntos[0].p.X;
            double x4 = c2.lista_puntos[c2.lista_puntos.Count - 1].p.X;
            double xi = vert[0];
            if (x2>x1 && xi>x1)
            {
                if (x4>x3 && xi<x4)
                {
                    return true;
                }
                if (x4<x3 && xi>x4)
                {
                    return true;
                }
            }
            if (x2<x1 && xi<x1)
            {
                if (x4 > x3 && xi < x4)
                {
                    return true;
                }
                if (x4 < x3 && xi > x4)
                {
                    return true;
                }
            }
            return false;
        }
    }




